class Solution:
    def maximumLength(self, nums: list) -> int:
        from collections import Counter
        cnt = Counter(nums)
        best = 1
        # handle x=1
        if 1 in cnt:
            c = cnt[1]
            best = c if c % 2 == 1 else c - 1
        for x in cnt:
            if x == 1:
                continue
            length = 0
            val = x
            while val in cnt and cnt[val] >= 2:
                length += 2
                if val > 10**9 // val:  # prevent overflow
                    break
                val = val * val
            if val in cnt and cnt[val] >= 1:
                length += 1
            best = max(best, length)
        return best

