var maximumLength = function(nums) {
    const cnt = new Map();
    for (const x of nums) cnt.set(x, (cnt.get(x) || 0) + 1);
    let best = 1;
    if (cnt.has(1)) {
        const c = cnt.get(1);
        best = c % 2 === 1 ? c : c - 1;
    }
    for (const [x] of cnt) {
        if (x === 1) continue;
        let length = 0, val = x;
        while (cnt.has(val) && cnt.get(val) >= 2) {
            length += 2;
            if (val > 1e9 / val) break;
            val = val * val;
        }
        if (cnt.has(val) && cnt.get(val) >= 1) length += 1;
        if (length > best) best = length;
    }
    return best;
};
